#include <stdio.h>

typedef enum { VAL_INT, VAL_FLOAT, VAL_STR } ValType;

typedef struct {
    ValType type;
    union {
        int i;
        float f;
        char s[32];
    } data;
} Value;

void print_value(const Value *v) {
    switch (v->type) {
        case VAL_INT:   printf("int: %d\n", v->data.i); break;
        case VAL_FLOAT: printf("float: %.1f\n", v->data.f); break;
        case VAL_STR:   printf("str: %s\n", v->data.s); break;
    }
}

int main(void) {
    Value vals[3];
    vals[0].type = VAL_INT;
    vals[0].data.i = 42;
    vals[1].type = VAL_FLOAT;
    vals[1].data.f = 3.14f;
    vals[2].type = VAL_STR;
    snprintf(vals[2].data.s, sizeof(vals[2].data.s), "hello");

    printf("sizeof(Value) = %zu\n", sizeof(Value));
    for (int k = 0; k < 3; k++)
        print_value(&vals[k]);
    return 0;
}

