void test_union_int_value(void) {
    Value v;
    v.type = VAL_INT;
    v.data.i = 42;
    TEST_ASSERT_EQUAL_INT(VAL_INT, v.type);
    TEST_ASSERT_EQUAL_INT(42, v.data.i);
}

void test_union_float_value(void) {
    Value v;
    v.type = VAL_FLOAT;
    v.data.f = 3.14f;
    TEST_ASSERT_EQUAL_INT(VAL_FLOAT, v.type);
    TEST_ASSERT_EQUAL_INT(3, (int)v.data.f);
}

void test_union_string_value(void) {
    Value v;
    v.type = VAL_STR;
    snprintf(v.data.s, sizeof(v.data.s), "hello");
    TEST_ASSERT_EQUAL_INT(VAL_STR, v.type);
    TEST_ASSERT_EQUAL_STRING("hello", v.data.s);
}

void test_union_tag_dispatch(void) {
    Value vals[3];
    vals[0].type = VAL_INT;
    vals[0].data.i = 99;
    vals[1].type = VAL_FLOAT;
    vals[1].data.f = 2.71f;
    vals[2].type = VAL_STR;
    snprintf(vals[2].data.s, sizeof(vals[2].data.s), "world");
    TEST_ASSERT_EQUAL_INT(99, vals[0].data.i);
    TEST_ASSERT_EQUAL_INT(2, (int)vals[1].data.f);
    TEST_ASSERT_EQUAL_STRING("world", vals[2].data.s);
}

int main(void) {
    RUN_TEST(test_union_int_value);
    RUN_TEST(test_union_float_value);
    RUN_TEST(test_union_string_value);
    RUN_TEST(test_union_tag_dispatch);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

