#include <stdio.h>

/* == EXEMPLE ================================================
 * Tagged union pour représenter des formes géométriques
 * Le tag ShapeType indique quel champ de l'union lire.
 * =========================================================== */
typedef enum { SHAPE_CIRCLE, SHAPE_RECT } ShapeType;
typedef struct {
    ShapeType type;
    union { float radius; struct { float w, h; } rect; } data;
} Shape;

void example_demo(void) {
    Shape shapes[2];
    shapes[0].type = SHAPE_CIRCLE;
    shapes[0].data.radius = 5.0f;
    shapes[1].type = SHAPE_RECT;
    shapes[1].data.rect.w = 3.0f;
    shapes[1].data.rect.h = 4.0f;
    for (int i = 0; i < 2; i++) {
        if (shapes[i].type == SHAPE_CIRCLE)
            printf("Circle r=%.1f\n", shapes[i].data.radius);
        else
            printf("Rect %.1fx%.1f\n", shapes[i].data.rect.w, shapes[i].data.rect.h);
    }
}
/* Resultat: Circle r=5.0 / Rect 3.0x4.0 */

